"""
电费账单自动化框架 - 插件系统
"""

import os
import importlib.util
import json
from typing import Dict, List, Optional, Any

class PluginManager:
    """插件管理器"""

    def __init__(self, plugins_dir: str):
        self.plugins_dir = plugins_dir
        self.plugins: Dict[str, Any] = {}

    def load_plugins(self) -> Dict[str, Any]:
        """加载所有插件"""
        self.plugins = {}

        if not os.path.exists(self.plugins_dir):
            return self.plugins

        for plugin_name in os.listdir(self.plugins_dir):
            plugin_path = os.path.join(self.plugins_dir, plugin_name)
            if os.path.isdir(plugin_path) and plugin_name != "__pycache__":
                plugin = self._load_plugin(plugin_name, plugin_path)
                if plugin:
                    self.plugins[plugin_name] = plugin

        return self.plugins

    def _load_plugin(self, plugin_name: str, plugin_path: str) -> Optional[Any]:
        """加载单个插件"""
        try:
            # 检查配置文件
            config_file = os.path.join(plugin_path, "config.json")
            if not os.path.exists(config_file):
                print(f"警告: 插件 {plugin_name} 缺少 config.json 文件")
                return None

            # 加载配置
            with open(config_file, 'r', encoding='utf-8') as f:
                config = json.load(f)

            # 检查是否启用
            if not config.get("enabled", True):
                print(f"信息: 插件 {plugin_name} 已禁用")
                return None

            # 加载处理器模块
            handler_file = os.path.join(plugin_path, "handler.py")
            if not os.path.exists(handler_file):
                print(f"警告: 插件 {plugin_name} 缺少 handler.py 文件")
                return None

            # 动态导入模块
            spec = importlib.util.spec_from_file_location(
                f"{plugin_name}_handler",
                handler_file
            )
            module = importlib.util.module_from_spec(spec)
            spec.loader.exec_module(module)

            # 获取处理器类（假设类名为 {PluginName}Handler）
            handler_class_name = f"{plugin_name.capitalize()}Handler"
            if hasattr(module, handler_class_name):
                handler_class = getattr(module, handler_class_name)
                return {
                    "name": plugin_name,
                    "config": config,
                    "handler_class": handler_class,
                    "path": plugin_path
                }
            else:
                print(f"警告: 插件 {plugin_name} 缺少 {handler_class_name} 类")
                return None

        except Exception as e:
            print(f"加载插件 {plugin_name} 时出错: {e}")
            return None

    def get_plugin(self, plugin_name: str) -> Optional[Any]:
        """获取指定插件"""
        return self.plugins.get(plugin_name)

    def list_plugins(self) -> List[str]:
        """列出所有已加载的插件"""
        return list(self.plugins.keys())

