"""
配置管理器 - 支持多级配置加载
"""

import os
import json
import yaml
import argparse
from typing import Dict, Any, Optional, List
from pathlib import Path

class ConfigManager:
    """配置管理器"""

    def __init__(self, config_path: Optional[str] = None):
        self.config_path = config_path
        self._config: Dict[str, Any] = {}
        self._loaded = False

        # 配置搜索路径
        self.search_paths = self._get_search_paths()

    def _get_search_paths(self) -> List[Path]:
        """获取配置搜索路径（按优先级从高到低）"""
        paths = []

        # 1. 环境变量指定的路径
        env_path = os.environ.get("ELECTRICITY_BILL_CONFIG")
        if env_path and os.path.exists(env_path):
            paths.append(Path(env_path))

        # 2. 命令行参数指定的路径
        if self.config_path and os.path.exists(self.config_path):
            paths.append(Path(self.config_path))

        # 3. 用户主目录配置文件
        home_config = Path.home() / ".electricity-bill" / "config.json"
        if home_config.exists():
            paths.append(home_config)

        # 4. 用户主目录YAML配置文件
        home_yaml = Path.home() / ".electricity-bill" / "config.yaml"
        if home_yaml.exists():
            paths.append(home_yaml)

        # 5. 项目配置文件（默认）
        default_config = Path(__file__).parent.parent / "config" / "framework_config.json"
        if default_config.exists():
            paths.append(default_config)

        # 6. 项目YAML配置文件
        default_yaml = Path(__file__).parent.parent / "config" / "framework_config.yaml"
        if default_yaml.exists():
            paths.append(default_yaml)

        return paths

    def _merge_configs(self, base: Dict[str, Any], override: Dict[str, Any]) -> Dict[str, Any]:
        """深度合并两个配置字典"""
        result = base.copy()

        for key, value in override.items():
            if key in result and isinstance(result[key], dict) and isinstance(value, dict):
                result[key] = self._merge_configs(result[key], value)
            else:
                result[key] = value

        return result

    def _load_config_file(self, file_path: Path) -> Dict[str, Any]:
        """加载配置文件（支持JSON和YAML）"""
        try:
            with open(file_path, 'r', encoding='utf-8') as f:
                if file_path.suffix in ['.yaml', '.yml']:
                    return yaml.safe_load(f) or {}
                else:
                    return json.load(f) or {}
        except (json.JSONDecodeError, yaml.YAMLError) as e:
            print(f"警告: 配置文件 {file_path} 格式错误: {e}")
            return {}
        except Exception as e:
            print(f"警告: 无法加载配置文件 {file_path}: {e}")
            return {}

    def _load_environment_variables(self) -> Dict[str, Any]:
        """加载环境变量配置"""
        config = {}

        # 框架配置
        if log_level := os.environ.get("ELECTRICITY_BILL_LOG_LEVEL"):
            config.setdefault("framework", {})["log_level"] = log_level

        if log_file := os.environ.get("ELECTRICITY_BILL_LOG_FILE"):
            config.setdefault("framework", {})["log_file"] = log_file

        # OneDrive配置
        if client_id := os.environ.get("ONEDRIVE_CLIENT_ID"):
            config.setdefault("onedrive", {})["client_id"] = client_id

        if client_secret := os.environ.get("ONEDRIVE_CLIENT_SECRET"):
            config.setdefault("onedrive", {})["client_secret"] = client_secret

        if tenant_id := os.environ.get("ONEDRIVE_TENANT_ID"):
            config.setdefault("onedrive", {})["tenant_id"] = tenant_id

        # VPN配置
        if vpn_server := os.environ.get("FORTIVPN_SERVER"):
            config.setdefault("vpn", {})["server"] = vpn_server

        if vpn_username := os.environ.get("FORTIVPN_USERNAME"):
            config.setdefault("vpn", {})["username"] = vpn_username

        if vpn_password := os.environ.get("FORTIVPN_PASSWORD"):
            config.setdefault("vpn", {})["password"] = vpn_password

        # 审核配置
        if ai_enabled := os.environ.get("AUDIT_AI_ENABLED"):
            config.setdefault("audit", {})["ai_enabled"] = ai_enabled.lower() == "true"

        if auto_submit_threshold := os.environ.get("AUTO_SUBMIT_THRESHOLD"):
            try:
                config.setdefault("audit", {})["auto_submit_threshold"] = float(auto_submit_threshold)
            except ValueError:
                pass

        return config

    def _apply_template_variables(self, config: Dict[str, Any]) -> Dict[str, Any]:
        """应用模板变量（如 {year}, {month} 等）"""
        # 这里可以添加更多的模板变量处理
        # 目前留空，可以在实际使用时扩展
        return config

    def load(self) -> Dict[str, Any]:
        """加载所有配置"""
        if self._loaded:
            return self._config

        # 从最低优先级开始（默认配置）
        base_config = {}

        # 1. 加载项目默认配置
        for config_path in reversed(self.search_paths):
            if config_path.exists():
                file_config = self._load_config_file(config_path)
                base_config = self._merge_configs(base_config, file_config)

        # 2. 加载环境变量配置（优先级更高）
        env_config = self._load_environment_variables()
        base_config = self._merge_configs(base_config, env_config)

        # 3. 应用模板变量
        self._config = self._apply_template_variables(base_config)

        # 4. 设置默认值
        self._set_defaults()

        self._loaded = True
        return self._config

    def _set_defaults(self):
        """设置默认配置值"""
        defaults = {
            "framework": {
                "name": "Electricity Bill Automation Framework",
                "version": "1.0.0",
                "log_level": "INFO",
                "log_file": None,
                "max_retries": 3,
                "retry_delay": 5,
                "temp_dir": "./temp"
            },
            "storage": {
                "type": "onedrive",
                "base_path": "/ElectricityBills/{year}/{month}/{mall_id}",
                "backup_enabled": True,
                "backup_dir": "./backup"
            },
            "audit": {
                "ai_enabled": True,
                "ai_model": "claude-3-sonnet",
                "auto_submit_threshold": 0.9,
                "human_review_threshold": 0.7,
                "notification_channels": ["console"]
            },
            "vpn": {
                "type": "fortivpn",
                "auto_connect": True,
                "timeout": 300,
                "retry_count": 3
            },
            "ocr": {
                "engine": "tesseract",
                "languages": ["chi_sim", "eng"],
                "timeout": 60,
                "cache_enabled": True
            }
        }

        for section, default_values in defaults.items():
            if section not in self._config:
                self._config[section] = default_values
            else:
                for key, value in default_values.items():
                    if key not in self._config[section]:
                        self._config[section][key] = value

    def get_config(self) -> Dict[str, Any]:
        """获取配置（如果未加载则自动加载）"""
        if not self._loaded:
            return self.load()
        return self._config

    def get_section(self, section: str) -> Dict[str, Any]:
        """获取指定配置节"""
        config = self.get_config()
        return config.get(section, {})

    def get_value(self, section: str, key: str, default: Any = None) -> Any:
        """获取指定配置值"""
        section_config = self.get_section(section)
        return section_config.get(key, default)

    def update_config(self, updates: Dict[str, Any]) -> None:
        """更新配置"""
        self._config = self._merge_configs(self._config, updates)

    def save_config(self, file_path: Optional[str] = None) -> bool:
        """保存配置到文件"""
        try:
            if not file_path:
                # 保存到第一个可写的搜索路径
                for config_path in self.search_paths:
                    try:
                        config_path.parent.mkdir(parents=True, exist_ok=True)
                        file_path = str(config_path)
                        break
                    except:
                        continue

                if not file_path:
                    # 默认保存到用户主目录
                    file_path = str(Path.home() / ".electricity-bill" / "config.json")

            # 确保目录存在
            Path(file_path).parent.mkdir(parents=True, exist_ok=True)

            with open(file_path, 'w', encoding='utf-8') as f:
                if file_path.endswith(('.yaml', '.yml')):
                    yaml.dump(self._config, f, default_flow_style=False, allow_unicode=True)
                else:
                    json.dump(self._config, f, ensure_ascii=False, indent=2)

            print(f"配置已保存到: {file_path}")
            return True

        except Exception as e:
            print(f"保存配置时出错: {e}")
            return False

    def validate_config(self) -> List[str]:
        """验证配置完整性，返回错误列表"""
        errors = []

        config = self.get_config()

        # 检查必要配置
        required_sections = ["framework", "storage", "audit"]
        for section in required_sections:
            if section not in config:
                errors.append(f"缺少必要配置节: {section}")

        # 检查存储配置
        storage_type = config.get("storage", {}).get("type")
        if storage_type == "onedrive":
            onedrive_config = config.get("onedrive", {})
            if not onedrive_config.get("client_id"):
                errors.append("OneDrive配置缺少 client_id")
            if not onedrive_config.get("client_secret"):
                errors.append("OneDrive配置缺少 client_secret")
            if not onedrive_config.get("tenant_id"):
                errors.append("OneDrive配置缺少 tenant_id")

        # 检查VPN配置（如果启用自动连接）
        vpn_config = config.get("vpn", {})
        if vpn_config.get("auto_connect", False):
            if not vpn_config.get("server"):
                errors.append("VPN配置缺少 server")
            if not vpn_config.get("username"):
                errors.append("VPN配置缺少 username")
            if not vpn_config.get("password"):
                errors.append("VPN配置缺少 password")

        # 检查OCR配置
        ocr_config = config.get("ocr", {})
        if ocr_config.get("engine") == "tesseract":
            # 检查Tesseract是否可用（这里只是占位符，实际检查需要运行时）
            pass

        return errors

    def reload(self) -> Dict[str, Any]:
        """重新加载配置"""
        self._loaded = False
        self._config = {}
        return self.load()

