            if config_path.exists():
                file_config = self._load_config_file(config_path)
                base_config = self._merge_configs(base_config, file_config)

        # 2. 加载环境变量配置（优先级更高）
        env_config = self._load_environment_variables()
        base_config = self._merge_configs(base_config, env_config)

        # 3. 应用模板变量
        self._config = self._apply_template_variables(base_config)

        # 4. 设置默认值
        self._set_defaults()

        self._loaded = True
        return self._config

    def _set_defaults(self):
        """设置默认配置值"""
        defaults = {
            "framework": {
                "name": "Electricity Bill Automation Framework",
                "version": "1.0.0",
                "log_level": "INFO",
                "log_file": None,
                "max_retries": 3,
                "retry_delay": 5,
                "temp_dir": "./temp"
            },
            "storage": {
                "type": "onedrive",
                "base_path": "/ElectricityBills/{year}/{month}/{mall_id}",
                "backup_enabled": True,
                "backup_dir": "./backup"
            },
            "audit": {
                "ai_enabled": True,
                "ai_model": "claude-3-sonnet",
                "auto_submit_threshold": 0.9,
                "human_review_threshold": 0.7,
                "notification_channels": ["console"]
            },
            "vpn": {
                "type": "fortivpn",
                "auto_connect": True,
                "timeout": 300,
                "retry_count": 3
            },
            "ocr": {
                "engine": "tesseract",
                "languages": ["chi_sim", "eng"],
                "timeout": 60,
                "cache_enabled": True
            }
        }

        for section, default_values in defaults.items():
            if section not in self._config:
                self._config[section] = default_values
            else:
                for key, value in default_values.items():
                    if key not in self._config[section]:
                        self._config[section][key] = value

    def get_config(self) -> Dict[str, Any]:
        """获取配置（如果未加载则自动加载）"""
        if not self._loaded:
            return self.load()
        return self._config

    def get_section(self, section: str) -> Dict[str, Any]:
        """获取指定配置节"""
        config = self.get_config()
        return config.get(section, {})

    def get_value(self, section: str, key: str, default: Any = None) -> Any:
        """获取指定配置值"""
        section_config = self.get_section(section)
        return section_config.get(key, default)

    def update_config(self, updates: Dict[str, Any]) -> None:
        """更新配置"""
        self._config = self._merge_configs(self._config, updates)

    def save_config(self, file_path: Optional[str] = None) -> bool:
        """保存配置到文件"""
        try:
            if not file_path:
                # 保存到第一个可写的搜索路径
                for config_path in self.search_paths:
                    try:
                        config_path.parent.mkdir(parents=True, exist_ok=True)
                        file_path = str(config_path)
                        break
                    except:
                        continue

                if not file_path:
                    # 默认保存到用户主目录
                    file_path = str(Path.home() / ".electricity-bill" / "config.json")

            # 确保目录存在
            Path(file_path).parent.mkdir(parents=True, exist_ok=True)

            with open(file_path, 'w', encoding='utf-8') as f:
                if file_path.endswith(('.yaml', '.yml')):
                    yaml.dump(self._config, f, default_flow_style=False, allow_unicode=True)
                else:
                    json.dump(self._config, f, ensure_ascii=False, indent=2)

            print(f"配置已保存到: {file_path}")
            return True

        except Exception as e:
            print(f"保存配置时出错: {e}")
            return False

    def validate_config(self) -> List[str]:
        """验证配置完整性，返回错误列表"""
        errors = []

        config = self.get_config()

        # 检查必要配置
        required_sections = ["framework", "storage", "audit"]
        for section in required_sections:
            if section not in config:
                errors.append(f"缺少必要配置节: {section}")

        # 检查存储配置
        storage_type = config.get("storage", {}).get("type")
        if storage_type == "onedrive":
            onedrive_config = config.get("onedrive", {})
            if not onedrive_config.get("client_id"):
                errors.append("OneDrive配置缺少 client_id")
            if not onedrive_config.get("client_secret"):
                errors.append("OneDrive配置缺少 client_secret")
            if not onedrive_config.get("tenant_id"):
                errors.append("OneDrive配置缺少 tenant_id")

        # 检查VPN配置（如果启用自动连接）
        vpn_config = config.get("vpn", {})
        if vpn_config.get("auto_connect", False):
            if not vpn_config.get("server"):
                errors.append("VPN配置缺少 server")
            if not vpn_config.get("username"):
                errors.append("VPN配置缺少 username")
            if not vpn_config.get("password"):
                errors.append("VPN配置缺少 password")

        # 检查OCR配置
        ocr_config = config.get("ocr", {})
        if ocr_config.get("engine") == "tesseract":
            # 检查Tesseract是否可用（这里只是占位符，实际检查需要运行时）
            pass

        return errors

    def reload(self) -> Dict[str, Any]:
        """重新加载配置"""
        self._loaded = False
        self._config = {}
        return self.load()
